                        lineHeight={1}
                     >
                       {'小\n豆\n子\n号'}
                     </Text>
                </group>

                {/* NAME LABEL 2 (Bottom) - Vertical Layout - Rotated to face downwards/outwards */}
                <group position={[0, 0, -0.36]} rotation={[0, Math.PI, 0]}>
