const Skybox: React.FC = () => {
  const meshRef = useRef<Mesh>(null);
  const starTextureUrl = useMemo(() => generateStarFieldTexture(), []);
  const starTexture = useMemo(() => {
    const t = new TextureLoader().load(starTextureUrl);
    // Important: Use RepeatWrapping to ensure seamless UV wrapping, 
    // although our content is manually wrapped, this helps with interpolation at the seam.
    t.wrapS = RepeatWrapping;
    t.wrapT = ClampToEdgeWrapping; // Vertical poles clamp
    return t;
  }, [starTextureUrl]);

  useFrame((state, delta) => {
    if (meshRef.current) {
      meshRef.current.rotation.y += delta * 0.0002; // Reduced from 0.0005
    }
  });

  return (
    <mesh ref={meshRef}>
      {/* Increased radius to ensure it encompasses the 3D Stars volume */}
      <sphereGeometry args={[500, 64, 64]} />
      <meshBasicMaterial 
        map={starTexture} 
        side={BackSide} 
        color="#ffffff"
      />
    </mesh>
  );
};

// Component to handle applying gesture inputs to OrbitControls
const OrbitController = ({ controlsRef, gestureVelocity }: { controlsRef: any, gestureVelocity: React.MutableRefObject<{dx: number, dy: number, gestureType: 'rotate' | 'zoom'}> }) => {
  useFrame(() => {
    if (controlsRef.current && controlsRef.current.enabled) {
      const { dx, dy, gestureType } = gestureVelocity.current;

      const threshold = 0.01;
      const isActive = Math.abs(dx) > threshold || Math.abs(dy) > threshold;

      if (isActive) {
          if (gestureType === 'rotate') {
             // ROTATE MODE
             // dx negative (Hand Left) -> rotate left -> map moves left.
             controlsRef.current.setAzimuthalAngle(controlsRef.current.getAzimuthalAngle() + dx * 0.05);

             // dy negative (Hand Up) -> Drag Map Up -> Camera looks down -> Angle Increase
             // dy positive (Hand Down) -> Drag Map Down -> Camera looks up -> Angle Decrease
             // We subtract dy to match "Drag" feel.
             controlsRef.current.setPolarAngle(controlsRef.current.getPolarAngle() - dy * 0.05);
          } else if (gestureType === 'zoom') {
             // ZOOM MODE (Pinch)
             // dy negative (Hand Up) -> Zoom In (dollyIn)
             // dy positive (Hand Down) -> Zoom Out (dollyOut)
             const zoomSpeed = 0.05;
             const zoomFactor = 1.0 + Math.abs(dy) * zoomSpeed;

             if (dy < 0) {
                 controlsRef.current.dollyIn(zoomFactor);
             } else {
                 controlsRef.current.dollyOut(zoomFactor);
             }
          }
          controlsRef.current.update();
      }
    }
  });
  return null;
}

const App: React.FC = () => {
  const [selectedPlanetId, setSelectedPlanetId] = useState<string | null>(null);
  const [isPaused, setIsPaused] = useState(false);
  const [simulationSpeed, setSimulationSpeed] = useState(1.0); // Default speed 1x
  const [isStarshipActive, setIsStarshipActive] = useState(false);
  const [showPluto, setShowPluto] = useState(false);
  const [isGestureMode, setIsGestureMode] = useState(false);

  const earthPositionRef = useRef<Vector3>(new Vector3(0, 0, 0));
  const planetRefs = useRef<{ [key: string]: Object3D }>({});
  const controlsRef = useRef<any>(null);

  // Ref to store current gesture velocity to avoid re-renders on every frame update
  const gestureVelocity = useRef<{dx: number, dy: number, gestureType: 'rotate' | 'zoom'}>({ dx: 0, dy: 0, gestureType: 'rotate' });

  const handleSelect = (id: string) => {
    setSelectedPlanetId(id);
    setIsPaused(true); // Stop orbit when a planet is selected
  };

  const handleClose = () => {
    setSelectedPlanetId(null);
    setIsPaused(false); // Resume orbit when closed
  };

  const togglePluto = () => {
    const newValue = !showPluto;
    setShowPluto(newValue);
    // If we are hiding Pluto and it is currently selected, deselect it
    if (!newValue && selectedPlanetId === 'pluto') {
      handleClose();
    }
  };

  const handleGestureControl = (dx: number, dy: number, gestureType: 'rotate' | 'zoom') => {
    gestureVelocity.current = { dx, dy, gestureType };
  };

  const toggleGestureMode = () => {
    const nextState = !isGestureMode;
    setIsGestureMode(nextState);
    if (nextState) {
      setSimulationSpeed(1.0);
    }
  };

  // Starship Management
  const handleToggleStarship = () => {
    const activating = !isStarshipActive;
    setIsStarshipActive(activating);

    if (activating) {
       // When starting mission: Stop manual pause (if any), set stable speed
       setIsPaused(false);
       setSimulationSpeed(0.5); // Slow down slightly for better flight viewing
    } else {
       // Manual cancel
       setSimulationSpeed(1.0);
    }
  };

  const handleMissionComplete = () => {
     // Called by Starship component when route is finished
     setIsStarshipActive(false);
     setSimulationSpeed(1.0); // Restore to 1x speed
  };

  // Find the selected planet object (Sun or normal Planet)
  const selectedPlanet = useMemo(() => {
    if (selectedPlanetId === 'sun') return SUN_DATA;
    return PLANETS.find(p => p.id === selectedPlanetId) || null;
  }, [selectedPlanetId]);

  // Filter planets based on showPluto state
  const displayedPlanets = useMemo(() => {
    return showPluto ? PLANETS : PLANETS.filter(p => p.id !== 'pluto');
  }, [showPluto]);

  return (
    <div className="w-full h-screen bg-black relative overflow-hidden">

      <UIOverlay 
        selectedPlanet={selectedPlanet}
        onClose={handleClose}
        isPaused={isPaused}
        togglePause={() => setIsPaused(!isPaused)}
        simulationSpeed={simulationSpeed}
        setSimulationSpeed={setSimulationSpeed}
        isStarshipActive={isStarshipActive}
        toggleStarship={handleToggleStarship}
        showPluto={showPluto}
        togglePluto={togglePluto}
        isGestureMode={isGestureMode}
        toggleGestureMode={toggleGestureMode}
      />

      {isGestureMode && (
        <GestureController 
          onControl={handleGestureControl} 
          onClose={() => setIsGestureMode(false)} 
        />
      )}

      <Canvas gl={{ antialias: true, toneMappingExposure: 1.2 }}>
        <Suspense fallback={null}>
          <PerspectiveCamera makeDefault position={[0, 80, 120]} fov={45} />

          <OrbitControls 
            ref={controlsRef}
            makeDefault
            enabled={!isStarshipActive} // Disable manual control when starship is active
            enableDamping={true}
            dampingFactor={0.05}
            enablePan={false}
            minDistance={20}
            maxDistance={300}
            maxPolarAngle={Math.PI / 1.8}
            // STOP auto-rotate when starship is active, or if user is interacting
            autoRotate={!selectedPlanetId && !isPaused && !isGestureMode && !isStarshipActive}
            autoRotateSpeed={0.15 * simulationSpeed}
          />

          <OrbitController controlsRef={controlsRef} gestureVelocity={gestureVelocity} />

          <Environment preset="city" environmentIntensity={0.3} />
          <pointLight position={[0, 0, 0]} intensity={2.5} distance={500} decay={1} color="#FFF5E0" />
          <ambientLight intensity={0.15} color="#404060" />

          {/* 1. Volumetric 3D Stars (Mid-distance) */}
          <Stars radius={400} depth={50} count={3000} factor={4} saturation={0.5} fade speed={0.5} />

          {/* 2. Painted Background (Infinite Distance) */}
          <Skybox />

          {/* 3. Magical Dust (Near-distance) */}
          <Sparkles count={400} scale={200} size={6} speed={0.2} opacity={0.4} noise={0.1} color="#88AAFF" />
          <Sparkles count={150} scale={150} size={3} speed={0.3} opacity={0.6} color="#FFD700" />

          <Sun 
             onSelect={handleSelect}
             isSelected={selectedPlanetId === 'sun'}
             isPaused={isPaused}
             simulationSpeed={simulationSpeed}
          />

          {/* Asteroid Belt located between Mars and Jupiter */}
          <AsteroidBelt isPaused={isPaused} simulationSpeed={simulationSpeed} />

          {displayedPlanets.map((planet) => (
            <Planet 
              key={planet.id} 
              data={planet} 
              isSelected={selectedPlanetId === planet.id}
              onSelect={handleSelect}
              isPaused={isPaused}
              simulationSpeed={simulationSpeed}
              earthPositionRef={earthPositionRef}
              planetRefs={planetRefs}
              isStarshipActive={isStarshipActive}
            />
          ))}

          {isStarshipActive && (
             <Starship 
                planetRefs={planetRefs} 
                onMissionComplete={handleMissionComplete}
             />
          )}

        </Suspense>
      </Canvas>
    </div>
  );
};

export default App;

import React, { useRef, useState, useEffect } from 'react';
import { useFrame } from '@react-three/fiber';
import { Vector3, Group, Object3D, AdditiveBlending, DoubleSide, Quaternion, MathUtils, Mesh } from 'three';
import { Trail, Html, Text } from '@react-three/drei';
import { PLANETS } from '../constants';

interface StarshipProps {
  planetRefs: React.MutableRefObject<{ [key: string]: Object3D }>;
  onMissionComplete: () => void;
}

// Updated State Machine
type ShipState = 'PLANNING' | 'TRAVELING' | 'ORBITING' | 'LEAVING' | 'COMPLETED';

// Visual Indicator for the target planet - SCI-FI BREATHING LIGHT
const TargetIndicator: React.FC<{ targetObj: Object3D; name: string }> = ({ targetObj, name }) => {
  const groupRef = useRef<Group>(null);
  const ringRef = useRef<Mesh>(null);
  const innerRingRef = useRef<Mesh>(null);
  const coreRef = useRef<Mesh>(null);

  useFrame((state, delta) => {
    if (groupRef.current && targetObj) {
      const worldPos = new Vector3();
      targetObj.getWorldPosition(worldPos);

      // Position marker significantly above the planet
      const hoverHeight = 15;
      groupRef.current.position.copy(worldPos).add(new Vector3(0, hoverHeight, 0));

      // Breathing Animation
      const t = state.clock.elapsedTime;
      const breathe = Math.sin(t * 3); // -1 to 1
      const scaleBase = 1.0 + breathe * 0.1; // 0.9 to 1.1

      // Bobbing
      groupRef.current.position.y += Math.sin(t * 2) * 0.5;

      // Ring Rotations
      if (ringRef.current) {
        ringRef.current.rotation.z += delta * 0.5;
        ringRef.current.rotation.x = Math.PI / 2 + Math.sin(t) * 0.1;
      }
      if (innerRingRef.current) {
         innerRingRef.current.rotation.z -= delta * 1.5;
         innerRingRef.current.scale.setScalar(0.8 + breathe * 0.05);
      }

      // Core pulsing
      if (coreRef.current) {
         const opacity = 0.6 + breathe * 0.3; // 0.3 to 0.9
         (coreRef.current.material as any).opacity = opacity;
         coreRef.current.scale.setScalar(1.0 + breathe * 0.2);
      }
    }
  });

  return (
    <group ref={groupRef}>
       {/* 1. Main Vertical Beam (Fading up) */}
       <mesh position={[0, -5, 0]}>
          <cylinderGeometry args={[0.2, 0.0, 15, 16, 1, true]} />
          <meshBasicMaterial 
            color="#00FFFF" 
            transparent 
            opacity={0.15} 
            blending={AdditiveBlending} 
            depthWrite={false} 
            side={DoubleSide}
          />
       </mesh>

       {/* 2. Outer Tech Ring */}
       <mesh ref={ringRef} rotation={[Math.PI / 2, 0, 0]}>
          <ringGeometry args={[2.5, 2.8, 6]} /> {/* Hexagonal ring */}
          <meshBasicMaterial color="#00FFFF" wireframe transparent opacity={0.5} side={DoubleSide} />
       </mesh>

       {/* 3. Inner Fast Ring */}
       <mesh ref={innerRingRef} rotation={[Math.PI / 2, 0, 0]}>
          <ringGeometry args={[1.5, 1.8, 32]} />
          <meshBasicMaterial color="#7DF9FF" transparent opacity={0.3} side={DoubleSide} />
       </mesh>

       {/* 4. Breathing Core */}
       <mesh ref={coreRef}>
          <sphereGeometry args={[0.8, 16, 16]} />
          <meshBasicMaterial color="#E0FFFF" transparent opacity={0.8} blending={AdditiveBlending} />
       </mesh>

       {/* 5. Glow Halo */}
       <mesh>
          <planeGeometry args={[6, 6]} />
          <meshBasicMaterial 
            color="#00FFFF" 
            transparent 
            opacity={0.2} 
            blending={AdditiveBlending} 
            depthWrite={false}
          /> 
       </mesh>

       {/* 6. Light Source */}
       <pointLight color="#00FFFF" distance={20} decay={2} intensity={3} />

       {/* 7. HUD Label */}
       <Html position={[0, 4, 0]} center sprite distanceFactor={15} zIndexRange={[100, 0]}>
          <div className="flex flex-col items-center gap-1">
             <div className="text-[12px] font-mono font-bold text-cyan-200 bg-black/60 border border-cyan-500/50 px-3 py-1 rounded-full backdrop-blur-md whitespace-nowrap shadow-[0_0_15px_rgba(0,255,255,0.4)] flex items-center gap-2">
                <span className="w-2 h-2 rounded-full bg-cyan-400 animate-pulse"></span>
                TARGET: {name}
             </div>
             <div className="text-[10px] text-cyan-500/80 font-mono tracking-widest">
               LOCKED & TRACKING
             </div>
          </div>
       </Html>
    </group>
  );
};

export const Starship: React.FC<StarshipProps> = ({ planetRefs, onMissionComplete }) => {
  const groupRef = useRef<Group>(null);
  const shipModelRef = useRef<Group>(null);

  // Logic State
  const [currentSpeedDisplay, setCurrentSpeedDisplay] = useState(0);
  const [missionProgress, setMissionProgress] = useState({ current: 0, total: 0, targetName: '' });

  // Refs for loop variables to avoid re-renders
  const stateRef = useRef<ShipState>('PLANNING');
  const initializedRef = useRef(false);
  const missionQueueRef = useRef<string[]>([]);
  const currentTargetIdRef = useRef<string | null>(null);

  // Movement calculation refs
  const currentSpeedRef = useRef(0);
  const orbitAngleRef = useRef(0);
  const orbitRadiusRef = useRef(15);
  const totalOrbitTraveledRef = useRef(0);
  const camDistRef = useRef(16); 

  // Leaving State Refs
  const exitVectorRef = useRef(new Vector3());
  const leavingTimeRef = useRef(0);

  // Smooth rotation
  const MAX_SPEED = 28; // Slightly faster for long trips
  const ORBIT_SPEED = 8; // Slower speed for orbiting

  // Helper to generate mission route
  const generateMission = () => {
     // Exclude Sun, Mercury (too hot/close), and ensure we have candidates
     const candidates = PLANETS
        .filter(p => p.id !== 'mercury')
        .map(p => p.id);

     const mission: string[] = [];
     let lastPlanet = 'earth'; // Start logic from earth (conceptually)

     // Pick 5 random planets
     for (let i = 0; i < 5; i++) {
        let next: string;
        let attempts = 0;
        // Find a candidate that is not the same as the last one
        do {
            next = candidates[Math.floor(Math.random() * candidates.length)];
            attempts++;
        } while (next === lastPlanet && attempts < 10);

        mission.push(next);
        lastPlanet = next;
     }

     // Finally, return to Earth
     mission.push('earth');

     return mission;
  };

  // Helper to calculate a safe but close orbit radius for each planet
  const getSafeOrbitRadius = (id: string) => {
     const p = PLANETS.find(x => x.id === id);
     if (!p) return 12; // Fallback

     if (p.hasRings) {
         return p.size * 2.5 + 2.0; 
     }
     return p.size * 2.8 + 2.0; 
  };

  useFrame((state, delta) => {
    if (!groupRef.current) return;

    // --- 0. INITIALIZATION: Spawn at Earth ---
    if (!initializedRef.current) {
      const earthObj = planetRefs.current['earth'];
      if (earthObj) {
        const startPos = new Vector3();
        earthObj.getWorldPosition(startPos);

        if (startPos.lengthSq() > 1) { // Wait until Earth has valid pos
             startPos.y += 10.0; // Start high
             startPos.x += 10.0; 
             groupRef.current.position.copy(startPos);
             groupRef.current.lookAt(new Vector3(0, 0, 0)); 
             initializedRef.current = true;
             stateRef.current = 'PLANNING';
        }
      }
      return; 
    }

    // --- 1. STATE MACHINE ---

    // PLANNING: Generate the queue once
    if (stateRef.current === 'PLANNING') {
       missionQueueRef.current = generateMission();
       stateRef.current = 'LEAVING'; // Start by "Leaving" spawn point to go to first target
       // Setup initial exit vector away from spawn
       const forward = new Vector3(0, 0, 1).applyQuaternion(groupRef.current.quaternion).normalize();
       exitVectorRef.current.copy(forward);
       leavingTimeRef.current = 0;
       return;
    }

    // LEAVING: Fly straight along the tangent (or initial vector)
    // Also acts as the "Transition" state between planets
    if (stateRef.current === 'LEAVING') {
       leavingTimeRef.current += delta;

       // Accelerate to cruise
       currentSpeedRef.current += (MAX_SPEED - currentSpeedRef.current) * 1.5 * delta;

       // Move along exit vector
       const moveVec = exitVectorRef.current.clone().multiplyScalar(currentSpeedRef.current * delta);
       groupRef.current.position.add(moveVec);

       // Banking reset
       if (shipModelRef.current) {
           shipModelRef.current.rotation.z = MathUtils.lerp(shipModelRef.current.rotation.z, 0, delta * 2);
       }

       // After flying away briefly (to clear orbit/spawn), select next target
       if (leavingTimeRef.current > 1.0) {
          // Check if we have a destination
          if (missionQueueRef.current.length > 0) {
             const nextId = missionQueueRef.current.shift()!;
             currentTargetIdRef.current = nextId;

             // Update HUD text
             const pName = PLANETS.find(p => p.id === nextId)?.name || nextId;
             setMissionProgress(prev => ({ 
                 current: 6 - missionQueueRef.current.length, // 5 steps + 1 return
                 total: 6,
                 targetName: pName
             }));

             stateRef.current = 'TRAVELING';
          } else {
             stateRef.current = 'COMPLETED';
          }
       }
    }

    // COMPLETED: Mission Done
    if (stateRef.current === 'COMPLETED') {
        // Trigger callback once then stop
        onMissionComplete();
        return;
    }

    // Common Target Position Logic
    let targetObj: Object3D | null = null;
    let targetPos = new Vector3();
    const tId = currentTargetIdRef.current;

    if (tId && planetRefs.current[tId]) {
      targetObj = planetRefs.current[tId];
      targetObj.getWorldPosition(targetPos);
    } else if (stateRef.current === 'TRAVELING') {
        // Target lost or invalid? Skip
        stateRef.current = 'LEAVING';
        return;
    }

    const currentPos = groupRef.current.position.clone();

    // TRAVELING: Fly towards the orbit entry point
    if (stateRef.current === 'TRAVELING' && targetObj) {
      const targetRadius = getSafeOrbitRadius(tId!);

      const dirToPlanet = new Vector3().subVectors(targetPos, currentPos).normalize();

      // Entry point logic: Aim for equator at target radius
      const flatDir = new Vector3(dirToPlanet.x, 0, dirToPlanet.z).normalize();
      const entryPoint = new Vector3(
          targetPos.x - flatDir.x * targetRadius,
          targetPos.y, 
          targetPos.z - flatDir.z * targetRadius
      );

      const distToEntry = currentPos.distanceTo(entryPoint);

      // Decelerate
      let targetSpeed = MAX_SPEED;
      if (distToEntry < 30) targetSpeed = ORBIT_SPEED;

      currentSpeedRef.current += (targetSpeed - currentSpeedRef.current) * 2.0 * delta;

      if (distToEntry < 2) {
         // Arrived
         stateRef.current = 'ORBITING';
         orbitRadiusRef.current = targetRadius;

         const relativePos = new Vector3().subVectors(currentPos, targetPos);
         orbitAngleRef.current = Math.atan2(relativePos.z, relativePos.x);
         totalOrbitTraveledRef.current = 0;
      } else {
         // Move
         const moveDir = new Vector3().subVectors(entryPoint, currentPos).normalize();
         groupRef.current.position.add(moveDir.multiplyScalar(currentSpeedRef.current * delta));

         // Rotate Ship
         const lookPos = currentPos.clone().add(moveDir);
         const slerpSpeed = distToEntry < 10 ? 3 * delta : 5 * delta;

         const dummyObj = new Object3D();
         dummyObj.position.copy(currentPos);
         dummyObj.lookAt(lookPos);
         groupRef.current.quaternion.slerp(dummyObj.quaternion, slerpSpeed);

         if (shipModelRef.current) {
            shipModelRef.current.rotation.z = MathUtils.lerp(shipModelRef.current.rotation.z, 0, delta * 2);
         }
      }
    }

    // ORBITING: Circle the planet
    if (stateRef.current === 'ORBITING' && targetObj) {
       currentSpeedRef.current += (ORBIT_SPEED - currentSpeedRef.current) * 2.0 * delta;

       const angularSpeed = currentSpeedRef.current / orbitRadiusRef.current;
       const angleDelta = angularSpeed * delta;

       orbitAngleRef.current += angleDelta;
       totalOrbitTraveledRef.current += angleDelta;

       const nextX = targetPos.x + Math.cos(orbitAngleRef.current) * orbitRadiusRef.current;
       const nextZ = targetPos.z + Math.sin(orbitAngleRef.current) * orbitRadiusRef.current;
       const nextY = targetPos.y; 

       const nextPos = new Vector3(nextX, nextY, nextZ);

       groupRef.current.position.copy(nextPos);

       // Look along tangent
       const futureAngle = orbitAngleRef.current + 0.1;
       const lookX = targetPos.x + Math.cos(futureAngle) * orbitRadiusRef.current;
       const lookZ = targetPos.z + Math.sin(futureAngle) * orbitRadiusRef.current;
       const lookY = targetPos.y; 

       const lookAtPos = new Vector3(lookX, lookY, lookZ);

       const dummyObj = new Object3D();
       dummyObj.position.copy(nextPos);
       dummyObj.lookAt(lookAtPos);
       groupRef.current.quaternion.slerp(dummyObj.quaternion, 8 * delta);

       // Bank
       if (shipModelRef.current) {
           shipModelRef.current.rotation.z = MathUtils.lerp(shipModelRef.current.rotation.z, -Math.PI / 4, delta * 3);
       }

       // Exit condition: ~1 full orbit (plus a bit to clear entry point)
       if (totalOrbitTraveledRef.current > Math.PI * 2.2) {
          stateRef.current = 'LEAVING';

          // Determine tangential exit vector
          const forward = new Vector3(0, 0, 1).applyQuaternion(groupRef.current.quaternion).normalize();
          exitVectorRef.current.copy(forward);
          leavingTimeRef.current = 0;

          // Note: We don't nullify currentTargetIdRef yet, we do that in LEAVING after some time
          // so the camera doesn't snap away too fast.
       }
    }

    // Update Speed Display
    const displayVal = Math.round(currentSpeedRef.current * 1000);
    if (Math.abs(displayVal - currentSpeedDisplay) > 100) {
        setCurrentSpeedDisplay(displayVal);
    }

    // --- CAMERA LOGIC (Third Person) ---
    const targetCamDist = stateRef.current === 'ORBITING' ? 35 : 18;
    camDistRef.current = MathUtils.lerp(camDistRef.current, targetCamDist, delta * 1.0);

    const shipForward = new Vector3(0, 0, 1).applyQuaternion(groupRef.current.quaternion).normalize();
    const heightOffset = MathUtils.lerp(5, 12, (camDistRef.current - 16) / (35 - 16));

    const camOffset = shipForward.clone().multiplyScalar(-camDistRef.current).add(new Vector3(0, heightOffset, 0));
    const desiredCamPos = groupRef.current.position.clone().add(camOffset);

    state.camera.position.lerp(desiredCamPos, 0.08);

    const lookTarget = groupRef.current.position.clone().add(shipForward.multiplyScalar(10));
    state.camera.lookAt(lookTarget);
  });

  const tId = currentTargetIdRef.current;
  const tName = missionProgress.targetName;

  return (
    <>
      {/* REALISTIC STARSHIP MODEL */}
      <group ref={groupRef} scale={[1.8, 1.8, 1.8]}>

        {/* Speedometer & Mission HUD */}
        <Html position={[2, 1, 0]} center transform sprite zIndexRange={[100, 0]}>
             <div className="flex flex-col items-start pointer-events-none select-none gap-2">

                {/* Velocity */}
                <div className="flex flex-col items-start">
                    <div className="bg-cyan-900/40 border-l-2 border-cyan-400 backdrop-blur-sm px-3 py-1 mb-1 transform skew-x-[-10deg]">
                       <span className="text-[10px] text-cyan-200 font-mono tracking-widest uppercase">Velocity</span>
                       <div className="text-xl font-bold text-white font-mono leading-none flex items-baseline gap-1">
                          {currentSpeedDisplay.toLocaleString()} 
                          <span className="text-[10px] text-cyan-400">KM/H</span>
                       </div>
                    </div>
                    <div className="flex gap-0.5 mt-0.5">
                       <div className={`h-1 w-2 rounded-sm ${currentSpeedRef.current > 5 ? 'bg-green-500' : 'bg-gray-700'}`}></div>
                       <div className={`h-1 w-2 rounded-sm ${currentSpeedRef.current > 10 ? 'bg-green-400' : 'bg-gray-700'}`}></div>
                       <div className={`h-1 w-2 rounded-sm ${currentSpeedRef.current > 15 ? 'bg-yellow-400' : 'bg-gray-700'}`}></div>
                       <div className={`h-1 w-2 rounded-sm ${currentSpeedRef.current > 20 ? 'bg-red-500' : 'bg-gray-700'}`}></div>
                    </div>
                </div>

                {/* Mission Status */}
                {missionProgress.total > 0 && (
                   <div className="bg-blue-900/40 border-l-2 border-blue-400 backdrop-blur-sm px-3 py-1 transform skew-x-[-10deg]">
                      <span className="text-[10px] text-blue-200 font-mono tracking-widest uppercase">Mission Log</span>
                      <div className="text-sm font-bold text-white leading-tight mt-0.5">
                         {tName.split(' ')[0]} 
                         <span className="text-[10px] ml-1 text-blue-300 opacity-80">
                           ({missionProgress.current}/{missionProgress.total})
                         </span>
                      </div>
                   </div>
                )}
             </div>
        </Html>

        {/* Inner group for banking animations (Rolling) */}
        <group ref={shipModelRef}>
            {/* Rotate entire ship mesh 90deg X so Y-up geometry faces Z-forward movement */}
            <group rotation={[Math.PI / 2, 0, 0]}>

                {/* 1. Main Hull */}
                <mesh position={[0, 0, 0]}>
                  <cylinderGeometry args={[0.35, 0.35, 1.6, 32]} />
                  <meshPhysicalMaterial 
                    color="#e2e8f0" 
                    metalness={0.9} 
                    roughness={0.2} 
                    clearcoat={1.0}
                    clearcoatRoughness={0.1}
                  />
                </mesh>

                {/* NAME LABEL 1 (Top) - Vertical Layout */}
                <group position={[0, 0, 0.36]}>
                     <Text
                        color="#2563eb" // Blue-600 (Science Blue)
                        fontSize={0.15}
                        anchorX="center"
                        anchorY="middle"
                        rotation={[0, 0, 0]} // Upright text
                        lineHeight={1}
                     >
                       {'小\n豆\n子\n号'}
                     </Text>
                </group>

                {/* NAME LABEL 2 (Bottom) - Vertical Layout - Rotated to face downwards/outwards */}
                <group position={[0, 0, -0.36]} rotation={[0, Math.PI, 0]}>
                     <Text
                        color="#2563eb" // Blue-600
                        fontSize={0.15}
                        anchorX="center"
                        anchorY="middle"
                        rotation={[0, 0, 0]} // Upright text
                        lineHeight={1}
                     >
                       {'小\n豆\n子\n号'}
                     </Text>
                </group>

                {/* 2. Nose Cone */}
                <mesh position={[0, 1.15, 0]}>
                  <coneGeometry args={[0.35, 0.7, 32]} />
                  <meshPhysicalMaterial 
                    color="#e2e8f0" 
                    metalness={0.9} 
                    roughness={0.2} 
                    clearcoat={1.0}
                  />
                </mesh>

                {/* 3. Forward Flaps */}
                <group position={[0, 1.0, 0]}>
                   <mesh position={[-0.32, 0, 0]} rotation={[0, 0, 0.2]}>
                      <boxGeometry args={[0.2, 0.3, 0.05]} />
                      <meshStandardMaterial color="#1a1a1a" roughness={0.4} />
                   </mesh>
                   <mesh position={[0.32, 0, 0]} rotation={[0, 0, -0.2]}>
                      <boxGeometry args={[0.2, 0.3, 0.05]} />
                      <meshStandardMaterial color="#1a1a1a" roughness={0.4} />
                   </mesh>
                </group>

                {/* 4. Aft Flaps */}
                <group position={[0, -0.6, 0]}>
                   <mesh position={[-0.45, 0, 0]} rotation={[0, 0, 0.1]}>
                      <boxGeometry args={[0.3, 0.6, 0.08]} />
                      <meshStandardMaterial color="#1a1a1a" roughness={0.4} />
                   </mesh>
                   <mesh position={[0.45, 0, 0]} rotation={[0, 0, -0.1]}>
                      <boxGeometry args={[0.3, 0.6, 0.08]} />
                      <meshStandardMaterial color="#1a1a1a" roughness={0.4} />
                   </mesh>
                </group>

                {/* 5. Engines */}
                <group position={[0, -0.85, 0]}>
                   <mesh position={[0, 0, 0]}>
                      <cylinderGeometry args={[0.25, 0.2, 0.1, 16]} />
                      <meshStandardMaterial color="#111" />
                   </mesh>
                   <mesh position={[0.1, -0.1, 0]}>
                       <cylinderGeometry args={[0.06, 0.08, 0.2, 8]} />
                       <meshStandardMaterial color="#222" />
                   </mesh>
                   <mesh position={[-0.1, -0.1, 0]}>
                       <cylinderGeometry args={[0.06, 0.08, 0.2, 8]} />
                       <meshStandardMaterial color="#222" />
                   </mesh>
                   <mesh position={[0, -0.1, 0.12]}>
                       <cylinderGeometry args={[0.06, 0.08, 0.2, 8]} />
                       <meshStandardMaterial color="#222" />
                   </mesh>
                </group>

                {/* 6. Raptor Engine Flame */}
                <mesh position={[0, -1.6, 0]}>
                  <cylinderGeometry args={[0.15, 0.0, 1.4, 16, 1, true]} /> 
                  <meshBasicMaterial 
                    color="#8B5CF6" 
                    transparent 
                    opacity={0.4} 
                    depthWrite={false} 
                    blending={AdditiveBlending}
                  />
                </mesh>
                <mesh position={[0, -1.4, 0]}>
                  <cylinderGeometry args={[0.1, 0.0, 1.0, 16, 1, true]} /> 
                  <meshBasicMaterial 
                    color="#06b6d4" 
                    transparent 
                    opacity={0.6} 
                    depthWrite={false} 
                    blending={AdditiveBlending}
                  />
                </mesh>
                 <mesh position={[0, -1.1, 0]}>
                  <cylinderGeometry args={[0.06, 0.0, 0.5, 8, 1, true]} /> 
                  <meshBasicMaterial 
                    color="#ffffff" 
                    transparent 
                    opacity={0.9} 
                    depthWrite={false} 
                    blending={AdditiveBlending}
                  />
                </mesh>

                <pointLight position={[0, -1, 0]} color="#06b6d4" distance={5} intensity={4} />
            </group>

            {/* TRAIL */}
            <group position={[0, 0, -1.2]}>
              <Trail width={0.4} length={6} color="#06b6d4" attenuation={(t) => t * t}>
                <mesh visible={false}><boxGeometry args={[0.1, 0.1, 0.1]} /></mesh>
              </Trail>
            </group>
        </group>
      </group>

      {/* TARGET INDICATOR */}
      {tId && planetRefs.current[tId] && stateRef.current === 'TRAVELING' && (
        <TargetIndicator targetObj={planetRefs.current[tId]} name={tName} />
      )}
    </>
  );
};

import React, { useRef, useState, useEffect } from 'react';
import { useFrame } from '@react-three/fiber';
import { Vector3, Group, Object3D, AdditiveBlending, DoubleSide, Quaternion, MathUtils, Mesh } from 'three';
import { Trail, Html, Text } from '@react-three/drei';
import { PLANETS } from '../constants';

interface StarshipProps {
  planetRefs: React.MutableRefObject<{ [key: string]: Object3D }>;
  onMissionComplete: () => void;
}

// Updated State Machine
type ShipState = 'PLANNING' | 'TRAVELING' | 'ORBITING' | 'LEAVING' | 'COMPLETED';

export const Starship: React.FC<StarshipProps> = ({ planetRefs, onMissionComplete }) => {
  const groupRef = useRef<Group>(null);
  const shipModelRef = useRef<Group>(null);

  // Logic State
  const [currentSpeedDisplay, setCurrentSpeedDisplay] = useState(0);
  const [missionProgress, setMissionProgress] = useState({ current: 0, total: 0, targetName: '' });

  // Refs for loop variables to avoid re-renders
  const stateRef = useRef<ShipState>('PLANNING');
  const initializedRef = useRef(false);
  const missionQueueRef = useRef<string[]>([]);
  const currentTargetIdRef = useRef<string | null>(null);

  // Movement calculation refs
  const currentSpeedRef = useRef(0);
  const orbitAngleRef = useRef(0);
  const orbitRadiusRef = useRef(15);
  const totalOrbitTraveledRef = useRef(0);
  const camDistRef = useRef(16); 

  // Leaving State Refs
  const exitVectorRef = useRef(new Vector3());
  const leavingTimeRef = useRef(0);

  // Smooth rotation
  const MAX_SPEED = 28; // Slightly faster for long trips
  const ORBIT_SPEED = 8; // Slower speed for orbiting

  // Helper to generate mission route
  const generateMission = () => {
     // Exclude Sun, Mercury (too hot/close), and ensure we have candidates
     const candidates = PLANETS
        .filter(p => p.id !== 'mercury')
        .map(p => p.id);

     const mission: string[] = [];
     let lastPlanet = 'earth'; // Start logic from earth (conceptually)

     // Pick 5 random planets
     for (let i = 0; i < 5; i++) {
        let next: string;
        let attempts = 0;
        // Find a candidate that is not the same as the last one
        do {
            next = candidates[Math.floor(Math.random() * candidates.length)];
            attempts++;
        } while (next === lastPlanet && attempts < 10);

        mission.push(next);
        lastPlanet = next;
     }

     // Finally, return to Earth
     mission.push('earth');

     return mission;
  };

  // Helper to calculate a safe but close orbit radius for each planet
  const getSafeOrbitRadius = (id: string) => {
     const p = PLANETS.find(x => x.id === id);
     if (!p) return 12; // Fallback

     if (p.hasRings) {
         return p.size * 2.5 + 2.0; 
     }
     return p.size * 2.8 + 2.0; 
  };

  useFrame((state, delta) => {
    if (!groupRef.current) return;

    // --- 0. INITIALIZATION: Spawn at Earth ---
    if (!initializedRef.current) {
      const earthObj = planetRefs.current['earth'];
      if (earthObj) {
        const startPos = new Vector3();
        earthObj.getWorldPosition(startPos);

        if (startPos.lengthSq() > 1) { // Wait until Earth has valid pos
             startPos.y += 10.0; // Start high
             startPos.x += 10.0; 
             groupRef.current.position.copy(startPos);
             groupRef.current.lookAt(new Vector3(0, 0, 0)); 
             initializedRef.current = true;
             stateRef.current = 'PLANNING';
        }
      }
      return; 
    }

    // --- 1. STATE MACHINE ---

    // PLANNING: Generate the queue once
    if (stateRef.current === 'PLANNING') {
       missionQueueRef.current = generateMission();
       stateRef.current = 'LEAVING'; // Start by "Leaving" spawn point to go to first target
       // Setup initial exit vector away from spawn
       const forward = new Vector3(0, 0, 1).applyQuaternion(groupRef.current.quaternion).normalize();
       exitVectorRef.current.copy(forward);
       leavingTimeRef.current = 0;
       return;
    }

    // LEAVING: Fly straight along the tangent (or initial vector)
    // Also acts as the "Transition" state between planets
    if (stateRef.current === 'LEAVING') {
       leavingTimeRef.current += delta;

       // Accelerate to cruise
       currentSpeedRef.current += (MAX_SPEED - currentSpeedRef.current) * 1.5 * delta;

       // Move along exit vector
       const moveVec = exitVectorRef.current.clone().multiplyScalar(currentSpeedRef.current * delta);
       groupRef.current.position.add(moveVec);

       // Banking reset
       if (shipModelRef.current) {
           shipModelRef.current.rotation.z = MathUtils.lerp(shipModelRef.current.rotation.z, 0, delta * 2);
       }

       // After flying away briefly (to clear orbit/spawn), select next target
       if (leavingTimeRef.current > 1.0) {
          // Check if we have a destination
          if (missionQueueRef.current.length > 0) {
             const nextId = missionQueueRef.current.shift()!;
             currentTargetIdRef.current = nextId;

             // Update HUD text
             const pName = PLANETS.find(p => p.id === nextId)?.name || nextId;
             setMissionProgress(prev => ({ 
                 current: 6 - missionQueueRef.current.length, // 5 steps + 1 return
                 total: 6,
                 targetName: pName
             }));

             stateRef.current = 'TRAVELING';
          } else {
             stateRef.current = 'COMPLETED';
          }
       }
    }

    // COMPLETED: Mission Done
    if (stateRef.current === 'COMPLETED') {
        // Trigger callback once then stop
        onMissionComplete();
        return;
    }

    // Common Target Position Logic
    let targetObj: Object3D | null = null;
    let targetPos = new Vector3();
    const tId = currentTargetIdRef.current;

    if (tId && planetRefs.current[tId]) {
      targetObj = planetRefs.current[tId];
      targetObj.getWorldPosition(targetPos);
    } else if (stateRef.current === 'TRAVELING') {
        // Target lost or invalid? Skip
        stateRef.current = 'LEAVING';
        return;
    }

    const currentPos = groupRef.current.position.clone();

    // TRAVELING: Fly towards the orbit entry point
    if (stateRef.current === 'TRAVELING' && targetObj) {
      const targetRadius = getSafeOrbitRadius(tId!);

      const dirToPlanet = new Vector3().subVectors(targetPos, currentPos).normalize();

      // Entry point logic: Aim for equator at target radius
      const flatDir = new Vector3(dirToPlanet.x, 0, dirToPlanet.z).normalize();
      const entryPoint = new Vector3(
          targetPos.x - flatDir.x * targetRadius,
          targetPos.y, 
          targetPos.z - flatDir.z * targetRadius
      );

      const distToEntry = currentPos.distanceTo(entryPoint);

      // Decelerate
      let targetSpeed = MAX_SPEED;
      if (distToEntry < 30) targetSpeed = ORBIT_SPEED;

      currentSpeedRef.current += (targetSpeed - currentSpeedRef.current) * 2.0 * delta;

      if (distToEntry < 2) {
         // Arrived
         stateRef.current = 'ORBITING';
         orbitRadiusRef.current = targetRadius;

         const relativePos = new Vector3().subVectors(currentPos, targetPos);
         orbitAngleRef.current = Math.atan2(relativePos.z, relativePos.x);
         totalOrbitTraveledRef.current = 0;
      } else {
         // Move
         const moveDir = new Vector3().subVectors(entryPoint, currentPos).normalize();
         groupRef.current.position.add(moveDir.multiplyScalar(currentSpeedRef.current * delta));

         // Rotate Ship
         const lookPos = currentPos.clone().add(moveDir);
         const slerpSpeed = distToEntry < 10 ? 3 * delta : 5 * delta;

         const dummyObj = new Object3D();
         dummyObj.position.copy(currentPos);
         dummyObj.lookAt(lookPos);
         groupRef.current.quaternion.slerp(dummyObj.quaternion, slerpSpeed);

         if (shipModelRef.current) {
            shipModelRef.current.rotation.z = MathUtils.lerp(shipModelRef.current.rotation.z, 0, delta * 2);
         }
      }
    }

    // ORBITING: Circle the planet
    if (stateRef.current === 'ORBITING' && targetObj) {
       currentSpeedRef.current += (ORBIT_SPEED - currentSpeedRef.current) * 2.0 * delta;

       const angularSpeed = currentSpeedRef.current / orbitRadiusRef.current;
       const angleDelta = angularSpeed * delta;

       orbitAngleRef.current += angleDelta;
       totalOrbitTraveledRef.current += angleDelta;

       const nextX = targetPos.x + Math.cos(orbitAngleRef.current) * orbitRadiusRef.current;
       const nextZ = targetPos.z + Math.sin(orbitAngleRef.current) * orbitRadiusRef.current;
       const nextY = targetPos.y; 

       const nextPos = new Vector3(nextX, nextY, nextZ);

       groupRef.current.position.copy(nextPos);

       // Look along tangent
       const futureAngle = orbitAngleRef.current + 0.1;
       const lookX = targetPos.x + Math.cos(futureAngle) * orbitRadiusRef.current;
       const lookZ = targetPos.z + Math.sin(futureAngle) * orbitRadiusRef.current;
       const lookY = targetPos.y; 

       const lookAtPos = new Vector3(lookX, lookY, lookZ);

       const dummyObj = new Object3D();
       dummyObj.position.copy(nextPos);
       dummyObj.lookAt(lookAtPos);
       groupRef.current.quaternion.slerp(dummyObj.quaternion, 8 * delta);

       // Bank
       if (shipModelRef.current) {
           shipModelRef.current.rotation.z = MathUtils.lerp(shipModelRef.current.rotation.z, -Math.PI / 4, delta * 3);
       }

       // Exit condition: ~1 full orbit (plus a bit to clear entry point)
       if (totalOrbitTraveledRef.current > Math.PI * 2.2) {
          stateRef.current = 'LEAVING';

          // Determine tangential exit vector
          const forward = new Vector3(0, 0, 1).applyQuaternion(groupRef.current.quaternion).normalize();
          exitVectorRef.current.copy(forward);
          leavingTimeRef.current = 0;

          // Note: We don't nullify currentTargetIdRef yet, we do that in LEAVING after some time
          // so the camera doesn't snap away too fast.
       }
    }

    // Update Speed Display
    const displayVal = Math.round(currentSpeedRef.current * 1000);
    if (Math.abs(displayVal - currentSpeedDisplay) > 100) {
        setCurrentSpeedDisplay(displayVal);
    }

    // --- CAMERA LOGIC (Third Person) ---
    const targetCamDist = stateRef.current === 'ORBITING' ? 35 : 18;
    camDistRef.current = MathUtils.lerp(camDistRef.current, targetCamDist, delta * 1.0);

    const shipForward = new Vector3(0, 0, 1).applyQuaternion(groupRef.current.quaternion).normalize();
    const heightOffset = MathUtils.lerp(5, 12, (camDistRef.current - 16) / (35 - 16));

    const camOffset = shipForward.clone().multiplyScalar(-camDistRef.current).add(new Vector3(0, heightOffset, 0));
    const desiredCamPos = groupRef.current.position.clone().add(camOffset);

    state.camera.position.lerp(desiredCamPos, 0.08);

    const lookTarget = groupRef.current.position.clone().add(shipForward.multiplyScalar(10));
    state.camera.lookAt(lookTarget);
  });

  const tId = currentTargetIdRef.current;
  const tName = missionProgress.targetName;

  return (
    <>
      {/* REALISTIC STARSHIP MODEL */}
      <group ref={groupRef} scale={[1.8, 1.8, 1.8]}>

        {/* Speedometer & Mission HUD */}
        <Html position={[2, 1, 0]} center transform sprite zIndexRange={[100, 0]}>
             <div className="flex flex-col items-start pointer-events-none select-none gap-2">

                {/* Velocity */}
                <div className="flex flex-col items-start">
                    <div className="bg-cyan-900/40 border-l-2 border-cyan-400 backdrop-blur-sm px-3 py-1 mb-1 transform skew-x-[-10deg]">
                       <span className="text-[10px] text-cyan-200 font-mono tracking-widest uppercase">Velocity</span>
                       <div className="text-xl font-bold text-white font-mono leading-none flex items-baseline gap-1">
                          {currentSpeedDisplay.toLocaleString()} 
                          <span className="text-[10px] text-cyan-400">KM/H</span>
                       </div>
                    </div>
                    <div className="flex gap-0.5 mt-0.5">
                       <div className={`h-1 w-2 rounded-sm ${currentSpeedRef.current > 5 ? 'bg-green-500' : 'bg-gray-700'}`}></div>
                       <div className={`h-1 w-2 rounded-sm ${currentSpeedRef.current > 10 ? 'bg-green-400' : 'bg-gray-700'}`}></div>
                       <div className={`h-1 w-2 rounded-sm ${currentSpeedRef.current > 15 ? 'bg-yellow-400' : 'bg-gray-700'}`}></div>
                       <div className={`h-1 w-2 rounded-sm ${currentSpeedRef.current > 20 ? 'bg-red-500' : 'bg-gray-700'}`}></div>
                    </div>
                </div>

                {/* Mission Status */}
                {missionProgress.total > 0 && (
                   <div className="bg-blue-900/40 border-l-2 border-blue-400 backdrop-blur-sm px-3 py-1 transform skew-x-[-10deg]">
                      <span className="text-[10px] text-blue-200 font-mono tracking-widest uppercase">Mission Log</span>
                      <div className="text-sm font-bold text-white leading-tight mt-0.5">
                         {tName.split(' ')[0]} 
                         <span className="text-[10px] ml-1 text-blue-300 opacity-80">
                           ({missionProgress.current}/{missionProgress.total})
                         </span>
                      </div>
                   </div>
                )}
             </div>
        </Html>

        {/* Inner group for banking animations (Rolling) */}
        <group ref={shipModelRef}>
            {/* Rotate entire ship mesh 90deg X so Y-up geometry faces Z-forward movement */}
            <group rotation={[Math.PI / 2, 0, 0]}>

                {/* 1. Main Hull */}
                <mesh position={[0, 0, 0]}>
                  <cylinderGeometry args={[0.35, 0.35, 1.6, 32]} />
                  <meshPhysicalMaterial 
                    color="#e2e8f0" 
                    metalness={0.9} 
                    roughness={0.2} 
                    clearcoat={1.0}
                    clearcoatRoughness={0.1}
                  />
                </mesh>

                {/* NAME LABEL 1 (Top) - Vertical Layout */}
                <group position={[0, 0, 0.36]}>
                     <Text
                        color="white" // White Glowing Text
                        fontSize={0.28} // Larger size
                        anchorX="center"
                        anchorY="middle"
                        rotation={[0, 0, 0]} 
                        lineHeight={1}
                        outlineWidth={0.02} // Glowing Outline
                        outlineColor="#00FFFF" // Cyan Glow
                     >
                       {'小\n豆\n子\n号'}
                     </Text>
                </group>

                {/* NAME LABEL 2 (Bottom) - Vertical Layout - Rotated to face downwards/outwards */}
                <group position={[0, 0, -0.36]} rotation={[0, Math.PI, 0]}>
                     <Text
                        color="white" // White Glowing Text
                        fontSize={0.28} // Larger size
                        anchorX="center"
                        anchorY="middle"
                        rotation={[0, 0, 0]} 
                        lineHeight={1}
                        outlineWidth={0.02} // Glowing Outline
                        outlineColor="#00FFFF" // Cyan Glow
                     >
                       {'小\n豆\n子\n号'}
                     </Text>
                </group>

                {/* 2. Nose Cone */}
                <mesh position={[0, 1.15, 0]}>
                  <coneGeometry args={[0.35, 0.7, 32]} />
                  <meshPhysicalMaterial 
                    color="#e2e8f0" 
                    metalness={0.9} 
                    roughness={0.2} 
                    clearcoat={1.0}
                  />
                </mesh>

                {/* 3. Forward Flaps */}
                <group position={[0, 1.0, 0]}>
                   <mesh position={[-0.32, 0, 0]} rotation={[0, 0, 0.2]}>
                      <boxGeometry args={[0.2, 0.3, 0.05]} />
                      <meshStandardMaterial color="#1a1a1a" roughness={0.4} />
