                    clearcoatRoughness={0.1}
                  />
                </mesh>

                {/* NAME LABEL 1 (Top) - Vertical Layout - GOLD & SPACED */}
                <group position={[0, 0, 0.36]}>
                     <Text
                        color="#FFD700" // Gold Color
                        fontSize={0.25} 
