                </group>

                {/* NAME LABEL 2 (Bottom) - Vertical Layout - Rotated - GOLD & SPACED */}
                <group position={[0, 0, -0.36]} rotation={[0, Math.PI, 0]}>
                     <Text
                        color="#FFD700" // Gold Color
