/**
 * Generates deep space starfield.
 */
export const generateStarFieldTexture = (): string => {
  const width = 2048; 
  const height = 1024;
  let svgContent = `
    <rect width="100%" height="100%" fill="#000000" />
    <defs>
      <filter id="nebulaBlur"><feGaussianBlur in="SourceGraphic" stdDeviation="60" /></filter>
      <filter id="starGlow"><feGaussianBlur in="SourceGraphic" stdDeviation="2" /></filter>
    </defs>
  `;
  const nebulaColors = ['#050714', '#0a081c', '#020410', '#08050c']; 
  const drawSeamlessEllipse = (cx: number, cy: number, rx: number, ry: number, fill: string, opacity: number) => {
      let str = `<ellipse cx="${cx}" cy="${cy}" rx="${rx}" ry="${ry}" fill="${fill}" opacity="${opacity}" filter="url(#nebulaBlur)" />`;
      if (cx - rx < 0) str += `<ellipse cx="${cx + width}" cy="${cy}" rx="${rx}" ry="${ry}" fill="${fill}" opacity="${opacity}" filter="url(#nebulaBlur)" />`;
      if (cx + rx > width) str += `<ellipse cx="${cx - width}" cy="${cy}" rx="${rx}" ry="${ry}" fill="${fill}" opacity="${opacity}" filter="url(#nebulaBlur)" />`;
      return str;
  };
  for (let i = 0; i < 6; i++) {
     const cx = Math.random() * width;
     const cy = Math.random() * height;
     const rx = Math.random() * 600 + 400;
     const ry = Math.random() * 500 + 200;
     const color = i % 2 === 0 ? '#0b1026' : '#120b29';
     svgContent += drawSeamlessEllipse(cx, cy, rx, ry, color, 0.3);
  }
  for (let i = 0; i < 15; i++) {
     const cx = Math.random() * width;
     const cy = Math.random() * height;
     const rx = Math.random() * 300 + 100;
     const ry = Math.random() * 200 + 100;
     const color = nebulaColors[Math.floor(Math.random() * nebulaColors.length)];
     svgContent += drawSeamlessEllipse(cx, cy, rx, ry, color, Math.random() * 0.2 + 0.1);
  }
  const drawSeamlessCircle = (cx: number, cy: number, r: number, fill: string, opacity: number, filter?: string) => {
      let str = `<circle cx="${cx}" cy="${cy}" r="${r}" fill="${fill}" opacity="${opacity}" ${filter ? `filter="${filter}"` : ''} />`;
      if (cx - r < 0) str += `<circle cx="${cx + width}" cy="${cy}" r="${r}" fill="${fill}" opacity="${opacity}" ${filter ? `filter="${filter}"` : ''} />`;
      if (cx + r > width) str += `<circle cx="${cx - width}" cy="${cy}" r="${r}" fill="${fill}" opacity="${opacity}" ${filter ? `filter="${filter}"` : ''} />`;
      return str;
  };
  for (let i = 0; i < 2000; i++) {
    const x = Math.random() * width;
    const y = Math.random() * height;
    svgContent += drawSeamlessCircle(x, y, Math.random() * 0.4 + 0.1, "#FFFFFF", Math.random() * 0.5 + 0.1);
  }
  for (let i = 0; i < 60; i++) {
      svgContent += drawSeamlessCircle(Math.random() * width, Math.random() * height, Math.random() * 1.5 + 0.5, "#ffffff", 0.8, "url(#starGlow)");
  }
  const svg = `<svg xmlns="http://www.w3.org/2000/svg" width="${width}" height="${height}" preserveAspectRatio="none" viewBox="0 0 ${width} ${height}">${svgContent}</svg>`;
  return `data:image/svg+xml;base64,${btoa(unescape(encodeURIComponent(svg)))}`;
};

