/**
 * Generates a deep space starfield texture with RICH NEBULAE and FINE STARDUST.
 * Inspired by NASA/JWST imagery.
 */
export const generateStarFieldTexture = (): string => {
  const width = 2048; 
  const height = 1024;

  // Base: Deep dark blue/black
  let svgContent = `
    <rect width="100%" height="100%" fill="#02040a" />
    <defs>
      <filter id="nebulaBlur">
        <feGaussianBlur in="SourceGraphic" stdDeviation="40" />
      </filter>
      <filter id="starGlow">
        <feGaussianBlur in="SourceGraphic" stdDeviation="1.5" />
      </filter>
    </defs>
  `;

  // Galactic Nebula Colors - Richer Palette
  const nebulaColors = ['#1e1b4b', '#312e81', '#4c1d95', '#1e3a8a', '#0f766e', '#581c87']; // Indigo, Purple, Blue, Teal, Violet

  // Helper for seamless ellipses (Nebulae)
  const drawSeamlessEllipse = (cx: number, cy: number, rx: number, ry: number, fill: string, opacity: number) => {
      let str = `<ellipse cx="${cx}" cy="${cy}" rx="${rx}" ry="${ry}" fill="${fill}" opacity="${opacity}" filter="url(#nebulaBlur)" />`;
      // Wrap X
      if (cx - rx < 0) str += `<ellipse cx="${cx + width}" cy="${cy}" rx="${rx}" ry="${ry}" fill="${fill}" opacity="${opacity}" filter="url(#nebulaBlur)" />`;
      if (cx + rx > width) str += `<ellipse cx="${cx - width}" cy="${cy}" rx="${rx}" ry="${ry}" fill="${fill}" opacity="${opacity}" filter="url(#nebulaBlur)" />`;
      return str;
  };

  // Draw Galactic Clouds
  for (let i = 0; i < 25; i++) {
     const cx = Math.random() * width;
     // Concentrate vertically somewhat to form a "plane" but spread out
     const dev = (Math.random() - 0.5) * height * 0.9;
     const cy = height/2 + dev; 

     const rx = Math.random() * 400 + 200;
     const ry = Math.random() * 250 + 100;
     const color = nebulaColors[Math.floor(Math.random() * nebulaColors.length)];
     const opacity = Math.random() * 0.15 + 0.05; 

     svgContent += drawSeamlessEllipse(cx, cy, rx, ry, color, opacity);
  }

  // Draw Stars
  const starColors = ["#ffffff", "#bfdbfe", "#fef3c7", "#e9d5ff"]; 

  const drawSeamlessStar = (cx: number, cy: number, r: number, fill: string, opacity: number, hasGlow: boolean) => {
      const glowAttr = hasGlow ? `filter="url(#starGlow)"` : '';
      let str = `<circle cx="${cx}" cy="${cy}" r="${r}" fill="${fill}" opacity="${opacity}" ${glowAttr} />`;
      if (cx < r) str += `<circle cx="${cx + width}" cy="${cy}" r="${r}" fill="${fill}" opacity="${opacity}" ${glowAttr} />`;
      if (cx > width - r) str += `<circle cx="${cx - width}" cy="${cy}" r="${r}" fill="${fill}" opacity="${opacity}" ${glowAttr} />`;
      return str;
  };

  // 1. Tiny background stars (Dust)
  for (let i = 0; i < 3500; i++) {
      const x = Math.random() * width;
      const y = Math.random() * height;
      const r = Math.random() * 0.5 + 0.1;
      const op = Math.random() * 0.4 + 0.1;
      svgContent += drawSeamlessStar(x, y, r, "#ffffff", op, false);
  }

  // 2. Medium stars (Main Sequence)
  for (let i = 0; i < 600; i++) {
      const x = Math.random() * width;
      const y = Math.random() * height;
      const r = Math.random() * 0.8 + 0.3;
      const color = starColors[Math.floor(Math.random() * starColors.length)];
      const op = Math.random() * 0.6 + 0.3;
      svgContent += drawSeamlessStar(x, y, r, color, op, false);
  }

  // 3. Small Asteroids (Replacements for big stars)
  const asteroidColors = ["#a8a29e", "#78716c", "#57534e", "#4b5563"]; // Stony/Metallic colors
  for (let i = 0; i < 150; i++) {
      const x = Math.random() * width;
      const y = Math.random() * height;
      const r = Math.random() * 1.2 + 0.5; // Small but visible
      const color = asteroidColors[Math.floor(Math.random() * asteroidColors.length)];
      // No glow, opaque-ish
      svgContent += drawSeamlessStar(x, y, r, color, 0.7, false);
  }

  const svg = `<svg xmlns="http://www.w3.org/2000/svg" width="${width}" height="${height}" preserveAspectRatio="none" viewBox="0 0 ${width} ${height}">${svgContent}</svg>`;
  return `data:image/svg+xml;base64,${btoa(unescape(encodeURIComponent(svg)))}`;
};

/**
 * Generates a procedural ring texture.
 * Customized for Saturn (realistic bands + gaps) and Uranus (thin dark rings).
 */
export const generateRingTexture = (planetId: string, baseColor: string): string => {
  const width = 1024;
  const height = 1024;

  let svgContent = '';

  if (planetId === 'saturn') {
    // NASA-like Saturn Rings
    // Colors: #C5AB6E (Base), #BFA667 (Darker), #EFEBCF (Lighter)
    // Structure: C Ring (Inner, Faint) -> B Ring (Brightest) -> Cassini Division (Gap) -> A Ring (Outer)
    svgContent = `
      <defs>
        <radialGradient id="saturnRing" cx="50%" cy="50%" r="50%" fx="50%" fy="50%">
          <!-- Inner Gap -->
          <stop offset="50%" style="stop-color:transparent;stop-opacity:0" />

          <!-- C Ring (Faint, semi-transparent, darker rock) -->
          <stop offset="55%" style="stop-color:#5A5040;stop-opacity:0.3" />
          <stop offset="63%" style="stop-color:#5A5040;stop-opacity:0.4" />

          <!-- Maxwell Gap approx -->
          <stop offset="63.5%" style="stop-color:#2a2a2a;stop-opacity:0.1" />

          <!-- B Ring (Bright, dense ice) -->
          <stop offset="64%" style="stop-color:#CDBA88;stop-opacity:0.8" />
          <stop offset="70%" style="stop-color:#EFEBCF;stop-opacity:1" /> <!-- Brightest part -->
          <stop offset="72%" style="stop-color:#D8C48E;stop-opacity:0.9" />
          <stop offset="75%" style="stop-color:#BFA667;stop-opacity:0.8" />

          <!-- Cassini Division (The Big Gap) -->
          <stop offset="75.5%" style="stop-color:#000000;stop-opacity:0.05" />
          <stop offset="78%" style="stop-color:#000000;stop-opacity:0.05" />

          <!-- A Ring (Outer, detailed) -->
          <stop offset="78.5%" style="stop-color:#A89870;stop-opacity:0.8" />
          <stop offset="85%" style="stop-color:#B0A076;stop-opacity:0.7" />

          <!-- Encke Gap (Small gap inside A Ring) -->
          <stop offset="86%" style="stop-color:#000000;stop-opacity:0.1" />
          <stop offset="86.5%" style="stop-color:#A89870;stop-opacity:0.7" />

          <stop offset="90%" style="stop-color:#958763;stop-opacity:0.6" />

          <!-- Outer Fade -->
          <stop offset="100%" style="stop-color:transparent;stop-opacity:0" />
        </radialGradient>

        <!-- Noise filter for granular look -->
        <filter id="ringNoise">
          <feTurbulence type="fractalNoise" baseFrequency="0.8" numOctaves="3" stitchTiles="stitch"/>
          <feColorMatrix type="saturate" values="0"/>
          <feComponentTransfer>
            <feFuncA type="linear" slope="0.3"/>
          </feComponentTransfer>
        </filter>
      </defs>

      <rect width="100%" height="100%" fill="url(#saturnRing)" />

      <!-- Add grain texture overlay -->
      <rect width="100%" height="100%" filter="url(#ringNoise)" opacity="0.4" style="mix-blend-mode: overlay;" />

      <!-- Subtle concentric lines for detail -->
      <circle cx="512" cy="512" r="300" stroke="#443322" stroke-width="1" fill="none" opacity="0.2" />
      <circle cx="512" cy="512" r="350" stroke="#443322" stroke-width="0.5" fill="none" opacity="0.2" />
      <circle cx="512" cy="512" r="400" stroke="#443322" stroke-width="1" fill="none" opacity="0.2" />
    `;
  } else if (planetId === 'uranus') {
    // Uranus Rings: 
    // Optimized for visibility with dual gradient approach (base glow + sharp bands).
    svgContent = `
      <defs>
        <radialGradient id="uranusBaseGlow" cx="50%" cy="50%" r="50%" fx="50%" fy="50%">
           <stop offset="40%" style="stop-color:transparent;stop-opacity:0" />

           <!-- Wide Soft Base Gradient (Cyan/Blue tint) -->
           <stop offset="50%" style="stop-color:#71C9CE;stop-opacity:0" />
           <stop offset="65%" style="stop-color:#A6E3E9;stop-opacity:0.15" />
           <stop offset="85%" style="stop-color:#CBF1F5;stop-opacity:0.25" />
           <stop offset="95%" style="stop-color:#71C9CE;stop-opacity:0" />
        </radialGradient>

        <radialGradient id="uranusBands" cx="50%" cy="50%" r="50%" fx="50%" fy="50%">
           <!-- Inner Ring -->
           <stop offset="58%" style="stop-color:#FFFFFF;stop-opacity:0" />
           <stop offset="59%" style="stop-color:#FFFFFF;stop-opacity:0.7" />
           <stop offset="60%" style="stop-color:#FFFFFF;stop-opacity:0" />

           <!-- Middle Ring -->
           <stop offset="70%" style="stop-color:#FFFFFF;stop-opacity:0" />
           <stop offset="71%" style="stop-color:#FFFFFF;stop-opacity:0.8" />
           <stop offset="72%" style="stop-color:#FFFFFF;stop-opacity:0" />

           <!-- Main Epsilon Ring (Wide and Bright) -->
           <stop offset="84%" style="stop-color:#FFFFFF;stop-opacity:0" />
           <stop offset="85%" style="stop-color:#E0FFFF;stop-opacity:0.9" /> 
           <stop offset="86%" style="stop-color:#FFFFFF;stop-opacity:1.0" />
           <stop offset="87%" style="stop-color:#E0FFFF;stop-opacity:0.9" />
           <stop offset="88%" style="stop-color:#FFFFFF;stop-opacity:0" />
        </radialGradient>
      </defs>

      <!-- 1. Soft Glow Base Layer -->
      <rect width="100%" height="100%" fill="url(#uranusBaseGlow)" />

      <!-- 2. Sharp Bands Layer -->
      <rect width="100%" height="100%" fill="url(#uranusBands)" />

      <!-- 3. Extra Strokes for high frequency definition -->
       <circle cx="512" cy="512" r="440" stroke="#FFFFFF" stroke-width="4" fill="none" opacity="0.8" />
       <circle cx="512" cy="512" r="364" stroke="#FFFFFF" stroke-width="2" fill="none" opacity="0.5" />
    `;
  } else {
    // Generic logic for other planets with rings
    svgContent = `
      <defs>
        <radialGradient id="ringGrad" cx="50%" cy="50%" r="50%" fx="50%" fy="50%">
          <stop offset="40%" style="stop-color:${baseColor};stop-opacity:0" />
          <stop offset="50%" style="stop-color:${baseColor};stop-opacity:0.2" />
          <stop offset="60%" style="stop-color:${baseColor};stop-opacity:0.9" />
          <stop offset="65%" style="stop-color:${baseColor};stop-opacity:0.3" />
          <stop offset="68%" style="stop-color:${baseColor};stop-opacity:0.8" />
          <stop offset="85%" style="stop-color:${baseColor};stop-opacity:0.8" />
          <stop offset="100%" style="stop-color:${baseColor};stop-opacity:0" />
        </radialGradient>
      </defs>
      <rect width="100%" height="100%" fill="url(#ringGrad)" />
      <circle cx="512" cy="512" r="360" stroke="${baseColor}" stroke-width="1" fill="none" opacity="0.3" />
      <circle cx="512" cy="512" r="400" stroke="${baseColor}" stroke-width="2" fill="none" opacity="0.2" />
      <circle cx="512" cy="512" r="440" stroke="${baseColor}" stroke-width="1" fill="none" opacity="0.3" />
    `;
  }

  const svg = `<svg xmlns="http://www.w3.org/2000/svg" width="${width}" height="${height}" viewBox="0 0 ${width} ${height}">${svgContent}</svg>`;
  return `data:image/svg+xml;base64,${btoa(unescape(encodeURIComponent(svg)))}`;
};

import React, { useState, Suspense, useRef, useMemo, useEffect } from 'react';
import { Canvas, useFrame } from '@react-three/fiber';
import { OrbitControls, Sparkles, PerspectiveCamera, Environment, Stars } from '@react-three/drei';
import { Vector3, TextureLoader, BackSide, Mesh, Object3D, RepeatWrapping, ClampToEdgeWrapping } from 'three';
import { PLANETS, SUN_DATA } from './constants';
import { Planet } from './components/Planet';
import { Sun } from './components/Sun';
import { Starship } from './components/Starship';
import { AsteroidBelt } from './components/AsteroidBelt';
import { UIOverlay } from './components/UIOverlay';
import { GestureController } from './components/GestureController';
import { generateStarFieldTexture } from './utils/textureGenerator';

const Skybox: React.FC = () => {
  const meshRef = useRef<Mesh>(null);
  const starTextureUrl = useMemo(() => generateStarFieldTexture(), []);
  const starTexture = useMemo(() => {
    const t = new TextureLoader().load(starTextureUrl);
    // Important: Use RepeatWrapping to ensure seamless UV wrapping, 
    // although our content is manually wrapped, this helps with interpolation at the seam.
    t.wrapS = RepeatWrapping;
    t.wrapT = ClampToEdgeWrapping; // Vertical poles clamp
    return t;
  }, [starTextureUrl]);

  useFrame((state, delta) => {
    if (meshRef.current) {
      meshRef.current.rotation.y += delta * 0.0002; // Reduced from 0.0005
    }
  });

  return (
    <mesh ref={meshRef}>
      {/* Increased radius to ensure it encompasses the 3D Stars volume */}
      <sphereGeometry args={[500, 64, 64]} />
      <meshBasicMaterial 
        map={starTexture} 
        side={BackSide} 
        color="#ffffff"
      />
    </mesh>
  );
};

// Component to handle applying gesture inputs to OrbitControls
const OrbitController = ({ controlsRef, gestureVelocity }: { controlsRef: any, gestureVelocity: React.MutableRefObject<{dx: number, dy: number, gestureType: 'rotate' | 'zoom'}> }) => {
  useFrame(() => {
    if (controlsRef.current && controlsRef.current.enabled) {
      const { dx, dy, gestureType } = gestureVelocity.current;

      const threshold = 0.01;
      const isActive = Math.abs(dx) > threshold || Math.abs(dy) > threshold;

      if (isActive) {
          if (gestureType === 'rotate') {
             // ROTATE MODE
             // dx negative (Hand Left) -> rotate left -> map moves left.
             controlsRef.current.setAzimuthalAngle(controlsRef.current.getAzimuthalAngle() + dx * 0.05);

             // dy negative (Hand Up) -> Drag Map Up -> Camera looks down -> Angle Increase
             // dy positive (Hand Down) -> Drag Map Down -> Camera looks up -> Angle Decrease
             // We subtract dy to match "Drag" feel.
             controlsRef.current.setPolarAngle(controlsRef.current.getPolarAngle() - dy * 0.05);
          } else if (gestureType === 'zoom') {
             // ZOOM MODE (Pinch)
             // dy negative (Hand Up) -> Zoom In (dollyIn)
             // dy positive (Hand Down) -> Zoom Out (dollyOut)
             const zoomSpeed = 0.05;
             const zoomFactor = 1.0 + Math.abs(dy) * zoomSpeed;

             if (dy < 0) {
                 controlsRef.current.dollyIn(zoomFactor);
             } else {
                 controlsRef.current.dollyOut(zoomFactor);
             }
          }
          controlsRef.current.update();
      }
    }
  });
  return null;
}

const App: React.FC = () => {
  const [selectedPlanetId, setSelectedPlanetId] = useState<string | null>(null);
  const [isPaused, setIsPaused] = useState(false);
  const [simulationSpeed, setSimulationSpeed] = useState(1.0); // Default speed 1x
  const [isStarshipActive, setIsStarshipActive] = useState(false);
  const [showPluto, setShowPluto] = useState(false);
  const [isGestureMode, setIsGestureMode] = useState(false);

  const earthPositionRef = useRef<Vector3>(new Vector3(0, 0, 0));
  const planetRefs = useRef<{ [key: string]: Object3D }>({});
  const controlsRef = useRef<any>(null);

  // Ref to store current gesture velocity to avoid re-renders on every frame update
  const gestureVelocity = useRef<{dx: number, dy: number, gestureType: 'rotate' | 'zoom'}>({ dx: 0, dy: 0, gestureType: 'rotate' });

  const handleSelect = (id: string) => {
    setSelectedPlanetId(id);
    setIsPaused(true); // Stop orbit when a planet is selected
  };

  const handleClose = () => {
    setSelectedPlanetId(null);
    setIsPaused(false); // Resume orbit when closed
  };

  const togglePluto = () => {
    const newValue = !showPluto;
    setShowPluto(newValue);
    // If we are hiding Pluto and it is currently selected, deselect it
    if (!newValue && selectedPlanetId === 'pluto') {
      handleClose();
    }
  };

  const handleGestureControl = (dx: number, dy: number, gestureType: 'rotate' | 'zoom') => {
    gestureVelocity.current = { dx, dy, gestureType };
  };

  const toggleGestureMode = () => {
    const nextState = !isGestureMode;
    setIsGestureMode(nextState);
    if (nextState) {
      setSimulationSpeed(1.0);
    }
  };

  // Starship Management
  const handleToggleStarship = () => {
    const activating = !isStarshipActive;
    setIsStarshipActive(activating);

    if (activating) {
       // When starting mission: PAUSE ORBITS so we have a static map
       setIsPaused(true); 
       setSimulationSpeed(0.5); // Slow down visuals slightly
    } else {
       // Manual cancel - Resume Orbits
       setIsPaused(false);
       setSimulationSpeed(1.0);
    }
  };

  const handleMissionComplete = () => {
     // Called by Starship component when route is finished
     setIsStarshipActive(false);
     setIsPaused(false); // RESUME ORBITS
     setSimulationSpeed(1.0); // Restore to 1x speed
  };

  // Find the selected planet object (Sun or normal Planet)
  const selectedPlanet = useMemo(() => {
    if (selectedPlanetId === 'sun') return SUN_DATA;
    return PLANETS.find(p => p.id === selectedPlanetId) || null;
  }, [selectedPlanetId]);

  // Filter planets based on showPluto state
  const displayedPlanets = useMemo(() => {
    return showPluto ? PLANETS : PLANETS.filter(p => p.id !== 'pluto');
  }, [showPluto]);

  return (
    <div className="w-full h-screen bg-black relative overflow-hidden">

      <UIOverlay 
        selectedPlanet={selectedPlanet}
        onClose={handleClose}
        isPaused={isPaused}
        togglePause={() => setIsPaused(!isPaused)}
        simulationSpeed={simulationSpeed}
        setSimulationSpeed={setSimulationSpeed}
        isStarshipActive={isStarshipActive}
        toggleStarship={handleToggleStarship}
        showPluto={showPluto}
        togglePluto={togglePluto}
        isGestureMode={isGestureMode}
        toggleGestureMode={toggleGestureMode}
      />

      {isGestureMode && (
        <GestureController 
          onControl={handleGestureControl} 
          onClose={() => setIsGestureMode(false)} 
        />
      )}

      <Canvas gl={{ antialias: true, toneMappingExposure: 1.2 }}>
        <Suspense fallback={null}>
          <PerspectiveCamera makeDefault position={[0, 80, 120]} fov={45} />

          <OrbitControls 
            ref={controlsRef}
            makeDefault
            enabled={!isStarshipActive} // Disable manual control when starship is active
            enableDamping={true}
            dampingFactor={0.05}
            enablePan={false}
            minDistance={20}
            maxDistance={300}
            maxPolarAngle={Math.PI / 1.8}
            // STOP auto-rotate when starship is active, or if user is interacting
            autoRotate={!selectedPlanetId && !isPaused && !isGestureMode && !isStarshipActive}
            autoRotateSpeed={0.15 * simulationSpeed}
          />

          <OrbitController controlsRef={controlsRef} gestureVelocity={gestureVelocity} />

          <Environment preset="city" environmentIntensity={0.3} />
          <pointLight position={[0, 0, 0]} intensity={2.5} distance={500} decay={1} color="#FFF5E0" />
          <ambientLight intensity={0.15} color="#404060" />

          {/* 1. Volumetric 3D Stars - Reduced factor to make them smaller (was 4) */}
          <Stars radius={400} depth={50} count={6000} factor={2} saturation={0.9} fade speed={0.5} />

          {/* 2. Painted Background (Infinite Distance) */}
          <Skybox />

          {/* 3. Magical Dust (Near-distance) */}
          <Sparkles count={300} scale={300} size={1.2} speed={0.2} opacity={0.4} noise={0.1} color="#a5b4fc" />
          <Sparkles count={100} scale={200} size={1} speed={0.3} opacity={0.5} color="#fcd34d" />

          <Sun 
             onSelect={handleSelect}
             isSelected={selectedPlanetId === 'sun'}
             isPaused={isPaused}
             simulationSpeed={simulationSpeed}
             planetRefs={planetRefs}
          />

          {/* Asteroid Belt located between Mars and Jupiter */}
          <AsteroidBelt isPaused={isPaused} simulationSpeed={simulationSpeed} />

          {displayedPlanets.map((planet) => (
            <Planet 
              key={planet.id} 
              data={planet} 
              isSelected={selectedPlanetId === planet.id}
              onSelect={handleSelect}
              isPaused={isPaused}
              simulationSpeed={simulationSpeed}
              earthPositionRef={earthPositionRef}
              planetRefs={planetRefs}
              isStarshipActive={isStarshipActive}
            />
          ))}

          {isStarshipActive && (
             <Starship 
                planetRefs={planetRefs} 
                onMissionComplete={handleMissionComplete}
             />
          )}

        </Suspense>
      </Canvas>
    </div>
  );
};

export default App;
